copy)
@@ -759,9 +759,10 @@ zfs_vget(vfs_t *vfsp, ino_t ino, int fla
 		VN_RELE(ZTOV(zp));
 		err =3D EINVAL;
 	}
-	if (err !=3D 0)
-		*vpp =3D NULL;
-	else {
+	if (err !=3D 0) {
+		/* try .zfs control directory */
+		err =3D zfsctl_vget(vfsp, ino, flags, vpp);
